/**
 * @name Taint flow from remote input to OS command execution
 * @description Tracks user-controlled input flowing into Runtime.exec() or ProcessBuilder
 * @kind path-problem
 * @problem.severity error
 * @id java/os-command-injection-remote
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module OsCommandConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Runtime.exec(String) - shell interpreted
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // ProcessBuilder constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // ProcessBuilder.command()
    exists(MethodCall mc |
      mc.getMethod().hasName("command") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module OsCommandFlow = TaintTracking::Global<OsCommandConfig>;
import OsCommandFlow::PathGraph

from OsCommandFlow::PathNode source, OsCommandFlow::PathNode sink
where OsCommandFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "OS command injection from $@.", source.getNode(), "remote user input"

/**
 * @name Script content used in OS command execution
 * @description Script content from user input flows into OS command execution
 * @kind path-problem
 * @problem.severity error
 * @id java/script-content-command-injection
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ScriptCommandConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Script content from HTTP forms/requests
    source instanceof RemoteFlowSource
    or
    // Parameters named "script" or "command" that come through form binding
    exists(Parameter p |
      p.getName().matches("%script%") or
      p.getName().matches("%command%") or
      p.getName().matches("%cmd%") or
      p.getName() = "script" or
      p.getName() = "command"
    |
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Runtime.exec variants
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // ProcessBuilder constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // ProcessBuilder.command()
    exists(MethodCall mc |
      mc.getMethod().hasName("command") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // GroovyShell.evaluate / parse / run
    exists(MethodCall mc |
      mc.getMethod().hasName(["evaluate", "parse", "run"]) and
      mc.getMethod().getDeclaringType().hasQualifiedName("groovy.lang", "GroovyShell") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module ScriptCommandFlow = TaintTracking::Global<ScriptCommandConfig>;
import ScriptCommandFlow::PathGraph

from ScriptCommandFlow::PathNode source, ScriptCommandFlow::PathNode sink
where ScriptCommandFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Script content flows into command/script execution from $@.", source.getNode(), "user input"

/**
 * @name SecureGroovyScript script field flows to GroovyShell without sandbox
 * @description Track if the script field bypasses sandbox and flows directly to GroovyShell.evaluate
 * @kind path-problem
 * @problem.severity error
 * @id java/secure-groovy-script-field-to-eval
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ScriptFieldConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // The 'script' field of SecureGroovyScript (set from user/form data)
    exists(Field f |
      f.getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.scriptsecurity.sandbox.groovy", "SecureGroovyScript") and
      f.hasName("script") and
      source.asExpr().(FieldAccess).getField() = f
    )
    or
    // The script parameter in ScriptApproval.using()
    exists(Method m, Parameter p |
      m.getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.scriptsecurity.scripts", "ScriptApproval") and
      m.hasName("using") and
      p = m.getAParameter() and
      p.getName() = "script" and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // GroovyShell.evaluate
    exists(MethodCall mc |
      mc.getMethod().hasName(["evaluate", "parse", "run"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyShell") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module ScriptFieldFlow = TaintTracking::Global<ScriptFieldConfig>;
import ScriptFieldFlow::PathGraph

from ScriptFieldFlow::PathNode source, ScriptFieldFlow::PathNode sink
where ScriptFieldFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Script content flows to GroovyShell.evaluate from $@.", source.getNode(), "script source"

/**
 * @name Argument injection in tool invocations with user-controlled parameters
 * @description Find cases where user-controlled data flows into command argument arrays for tools like git, curl, etc.
 * @kind path-problem
 * @problem.severity error
 * @id java/argument-injection-tools
 * @tags security
 *       external/cwe/cwe-088
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ArgInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
    or
    // Script/command content parameters
    exists(Parameter p |
      p.getName().toLowerCase().matches(["%script%", "%command%", "%cmd%", "%url%", "%path%", "%arg%"]) and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ProcessBuilder with array/list arguments
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("command") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Runtime.exec with String array
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Arrays used to build command lists (add to list used in ProcessBuilder)
    exists(MethodCall mc |
      mc.getMethod().hasName("add") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.util", "List") and
      sink.asExpr() = mc.getArgument(0) and
      exists(MethodCall pb |
        (pb.getMethod().hasName("command") or pb.getMethod().hasName("exec")) and
        DataFlow::localFlow(DataFlow::exprNode(mc.getQualifier()), DataFlow::exprNode(pb.getAnArgument()))
      )
    )
  }
}

module ArgInjectionFlow = TaintTracking::Global<ArgInjectionConfig>;
import ArgInjectionFlow::PathGraph

from ArgInjectionFlow::PathNode source, ArgInjectionFlow::PathNode sink
where ArgInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Argument injection: user input flows into command argument from $@.", source.getNode(), "user input"

/**
 * @name Remote input to GroovyShell via configuring/using approval chain
 * @description Full taint path from RemoteFlowSource through configuring/using to GroovyShell.evaluate
 * @kind path-problem
 * @problem.severity error
 * @id java/remote-to-groovyshell-approval-chain
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module RemoteToGroovyConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // GroovyShell.evaluate - the final execution point
    exists(MethodCall mc |
      mc.getMethod().hasName(["evaluate", "parse", "run"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyShell") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // ScriptEngine.eval - other script engines
    exists(MethodCall mc |
      mc.getMethod().hasName("eval") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.script", "ScriptEngine") and
      sink.asExpr() = mc.getArgument(0)
    )
  }

  predicate isAdditionalFlowStep(DataFlow::Node node1, DataFlow::Node node2) {
    // ScriptApproval.using() returns its script parameter - model this flow
    exists(Method usingMethod, ReturnStmt rs |
      usingMethod.getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.scriptsecurity.scripts", "ScriptApproval") and
      usingMethod.hasName("using") and
      rs.getEnclosingCallable() = usingMethod and
      node1.asExpr() = rs.getResult() and
      node2.asExpr().(MethodCall).getMethod() = usingMethod
    )
    or
    // ScriptApproval.configuring() returns its script parameter
    exists(Method configuringMethod, ReturnStmt rs |
      configuringMethod.getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.scriptsecurity.scripts", "ScriptApproval") and
      configuringMethod.hasName("configuring") and
      rs.getEnclosingCallable() = configuringMethod and
      node1.asExpr() = rs.getResult() and
      node2.asExpr().(MethodCall).getMethod() = configuringMethod
    )
  }
}

module RemoteToGroovyFlow = TaintTracking::Global<RemoteToGroovyConfig>;
import RemoteToGroovyFlow::PathGraph

from RemoteToGroovyFlow::PathNode source, RemoteToGroovyFlow::PathNode sink
where RemoteToGroovyFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Remote input flows to GroovyShell execution from $@.", source.getNode(), "remote user input"

/**
 * @name ScriptApproval configuring with approveIfAdmin - admin script auto-approval to execution
 * @description Check if scripts submitted by admins are auto-approved and flow directly to execution
 * @kind path-problem
 * @problem.severity error
 * @id java/admin-auto-approved-script-to-exec
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module AdminApprovalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // configuring() call where approveIfAdmin=true, indicating admin-approved path
    exists(MethodCall mc |
      mc.getMethod().hasName("configuring") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.scriptsecurity.scripts", "ScriptApproval") and
      // Check for calls with 4 params (including approveIfAdmin)
      mc.getNumArgument() >= 3 and
      source.asExpr() = mc
    )
    or
    // using() return value - script that passed (or bypassed) approval
    exists(MethodCall mc |
      mc.getMethod().hasName("using") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.scriptsecurity.scripts", "ScriptApproval") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // GroovyShell.evaluate
    exists(MethodCall mc |
      mc.getMethod().hasName(["evaluate", "parse", "run"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyShell") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Runtime.exec
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // ProcessBuilder
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module AdminApprovalFlow = TaintTracking::Global<AdminApprovalConfig>;
import AdminApprovalFlow::PathGraph

from AdminApprovalFlow::PathNode source, AdminApprovalFlow::PathNode sink
where AdminApprovalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Auto-approved script content flows to execution from $@.", source.getNode(), "approval source"
